import React from "react";
import "./article.css";
import e from "express";

const Article = () => {
            return (
            <>
            <div className="article_container">
            <div className="article_img__box">
                        <img className="article_img" src="" alt=""  />
            </div>      
            <div className="aricle_section">
                        <div className="article_title">
                             <span className="article_title__text"></span>
                        </div>
                        <div className="article_content">
                         <p className="article_content__text"></p>
                        </div>
                        <div className="article_more">
                            <button className="article_like__btn">like</button>
                            <span className="like_count"></span>
                        </div>
            </div>      
             </div>
            </>
            )};
export default Article;
